import React, { useState, useEffect, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import data1Video from '../assets/videos/vid1.mp4';
import data2Video from '../assets/videos/vid2.mp4';
import data3Video from '../assets/videos/vid3.mp4';
import data4Video from '../assets/videos/vid4.mp4';
import data5Video from '../assets/videos/vid5.mp4';
import data6Video from '../assets/videos/vid6.mp4';

const NewsSection = () => {
    const { t } = useTranslation();
    const [filter, setFilter] = useState('all');
    const [loadedVideos, setLoadedVideos] = useState({});
    const [isVisible, setIsVisible] = useState(false);
    const [hoveredItem, setHoveredItem] = useState(null);
    const sectionRef = useRef(null);

    useEffect(() => {
        const observer = new IntersectionObserver(
            ([entry]) => {
                if (entry.isIntersecting) {
                    setIsVisible(true);
                }
            },
            { threshold: 0.1 }
        );

        if (sectionRef.current) {
            observer.observe(sectionRef.current);
        }

        return () => {
            if (sectionRef.current) {
                observer.unobserve(sectionRef.current);
            }
        };
    }, []);

    const handleVideoLoad = (id) => {
        setLoadedVideos(prev => ({...prev, [id]: true}));
    };

    const newsItems = [
        {
            id: 1,
            date: t('newsSection.items.techSymposium.date'),
            title: t('newsSection.items.techSymposium.title'),
            excerpt: t('newsSection.items.techSymposium.excerpt'),
            videoSrc: data1Video,
            fullContent: "/news/tech-symposium",
            category: "event",
            icon: "event",
            featured: true
        },
        {
            id: 2,
            date: t('newsSection.items.industryPartnership.date'),
            title: t('newsSection.items.industryPartnership.title'),
            excerpt: t('newsSection.items.industryPartnership.excerpt'),
            videoSrc: data2Video,
            fullContent: "/news/industry-partnership",
            category: "news",
            icon: "campaign"
        },
        {
            id: 3,
            date: t('newsSection.items.springOpenHouse.date'),
            title: t('newsSection.items.springOpenHouse.title'),
            excerpt: t('newsSection.items.springOpenHouse.excerpt'),
            videoSrc: data3Video,
            fullContent: "/news/spring-open-house",
            category: "event",
            icon: "event"
        },
        {
            id: 4,
            date: t('newsSection.items.studentAwards.date'),
            title: t('newsSection.items.studentAwards.title'),
            excerpt: t('newsSection.items.studentAwards.excerpt'),
            videoSrc: data4Video,
            fullContent: "/news/student-awards",
            category: "news",
            icon: "emoji_events"
        },
        {
            id: 5,
            date: t('newsSection.items.careerFair.date'),
            title: t('newsSection.items.careerFair.title'),
            excerpt: t('newsSection.items.careerFair.excerpt'),
            videoSrc: data5Video,
            fullContent: "/news/career-fair",
            category: "event",
            icon: "business_center"
        },
        {
            id: 6,
            date: t('newsSection.items.aiLab.date'),
            title: t('newsSection.items.aiLab.title'),
            excerpt: t('newsSection.items.aiLab.excerpt'),
            videoSrc: data6Video,
            fullContent: "/news/ai-lab",
            category: "news",
            icon: "psychology"
        }
    ];

    const filteredNews = filter === 'all' 
        ? newsItems 
        : newsItems.filter(item => item.category === filter);

    const getAnimationDelay = (index) => {
        return `${index * 100}ms`;
    };

    const getCategoryColor = (category) => {
        return category === 'event' ? 'from-blue-500 to-indigo-600' : 'from-purple-500 to-pink-600';
    };

    const getCategoryBgColor = (category) => {
        return category === 'event' ? 'bg-blue-100 text-blue-700' : 'bg-purple-100 text-purple-700';
    };

    return (
        <section 
            ref={sectionRef}
            className="py-20 bg-gradient-to-br from-gray-50 via-white to-gray-50 relative overflow-hidden"
            id="news"
        >
            {/* Background Decoration */}
            <div className="absolute inset-0 opacity-5">
                <div className="absolute top-0 right-0 w-96 h-96 bg-gradient-to-br from-blue-400 to-purple-600 rounded-full blur-3xl"></div>
                <div className="absolute bottom-0 left-0 w-96 h-96 bg-gradient-to-br from-purple-400 to-pink-600 rounded-full blur-3xl"></div>
            </div>

            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
                {/* Section Header */}
                <div className="text-center mb-16">
                    <div className="inline-flex items-center px-4 py-2 bg-gradient-to-r from-blue-100 to-purple-100 rounded-full text-blue-800 text-sm font-medium mb-4">
                        <span className="material-icons text-lg mr-2">newspaper</span>
                        Latest Updates
                    </div>
                    <h2 className="text-4xl md:text-5xl font-bold text-gray-900 mb-6">
                        {t('newsSection.header.title')}
                    </h2>
                    <p className="text-xl text-gray-600 max-w-3xl mx-auto">
                        {t('newsSection.header.subtitle')}
                    </p>
                </div>

                {/* Modern Filter Pills */}
                <div className="flex justify-center mb-12">
                    <div className="inline-flex bg-gray-100 rounded-full p-1 space-x-1">
                        {['all', 'news', 'event'].map((category) => (
                            <button
                                key={category}
                                onClick={() => setFilter(category)}
                                className={`
                                    px-6 py-2.5 rounded-full font-medium text-sm transition-all duration-300
                                    ${filter === category 
                                        ? 'bg-white text-gray-900 shadow-lg' 
                                        : 'text-gray-600 hover:text-gray-900'}
                                `}
                            >
                                {category === 'all' ? t('newsSection.filters.all') : 
                                 category === 'news' ? t('newsSection.filters.news') : 
                                 t('newsSection.filters.events')}
                            </button>
                        ))}
                    </div>
                </div>

                {/* News Grid with Modern Cards */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {filteredNews.map((item, index) => (
                        <div
                            key={item.id}
                            className={`
                                group relative transform transition-all duration-700 
                                ${isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-8'}
                            `}
                            style={{ transitionDelay: getAnimationDelay(index) }}
                            onMouseEnter={() => setHoveredItem(item.id)}
                            onMouseLeave={() => setHoveredItem(null)}
                        >
                            <div className="bg-white rounded-2xl shadow-lg hover:shadow-2xl transition-all duration-500 overflow-hidden h-full flex flex-col">
                                {/* Video Container with Overlay */}
                                <div className="relative h-56 overflow-hidden">
                                    {!loadedVideos[item.id] && (
                                        <div className="absolute inset-0 bg-gray-200 animate-pulse flex items-center justify-center">
                                            <div className="flex flex-col items-center">
                                                <div className="w-12 h-12 border-4 border-gray-300 border-t-blue-600 rounded-full animate-spin mb-2"></div>
                                                <span className="text-sm text-gray-500">{t('newsSection.loading')}</span>
                                            </div>
                                        </div>
                                    )}
                                    <video 
                                        controls={hoveredItem === item.id}
                                        autoPlay 
                                        muted 
                                        loop 
                                        onLoadedData={() => handleVideoLoad(item.id)}
                                        className={`
                                            w-full h-full object-cover transition-all duration-500
                                            ${loadedVideos[item.id] ? 'opacity-100' : 'opacity-0'}
                                            ${hoveredItem === item.id ? 'scale-110' : 'scale-100'}
                                        `}
                                    >
                                        <source src={item.videoSrc} type="video/mp4" />
                                        {t('newsSection.videoNotSupported')}
                                    </video>

                                    {/* Gradient Overlay */}
                                    <div className={`
                                        absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent 
                                        transition-opacity duration-300
                                        ${hoveredItem === item.id ? 'opacity-0' : 'opacity-100'}
                                    `}></div>

                                    {/* Featured Badge */}
                                    {item.featured && (
                                        <div className="absolute top-4 left-4 px-3 py-1.5 bg-gradient-to-r from-orange-500 to-red-500 text-white text-xs font-semibold rounded-full flex items-center gap-1 shadow-lg">
                                            <span className="material-icons text-sm">star</span>
                                            Featured
                                        </div>
                                    )}

                                    {/* Category Icon */}
                                    <div className={`
                                        absolute bottom-4 right-4 w-12 h-12 rounded-full 
                                        bg-gradient-to-r ${getCategoryColor(item.category)}
                                        flex items-center justify-center text-white shadow-lg
                                        transform transition-transform duration-300
                                        ${hoveredItem === item.id ? 'scale-110 rotate-12' : 'scale-100 rotate-0'}
                                    `}>
                                        <span className="material-icons">{item.icon}</span>
                                    </div>
                                </div>

                                {/* Content */}
                                <div className="p-6 flex-grow flex flex-col">
                                    <div className="flex items-center justify-between mb-3">
                                        <span className={`
                                            px-3 py-1 rounded-full text-xs font-medium
                                            ${getCategoryBgColor(item.category)}
                                        `}>
                                            {item.category === 'event' ? t('newsSection.categoryLabels.event') : t('newsSection.categoryLabels.news')}
                                        </span>
                                        <span className="text-sm text-gray-500 flex items-center gap-1">
                                            <span className="material-icons text-sm">schedule</span>
                                            {item.date}
                                        </span>
                                    </div>

                                    <h3 className="text-xl font-bold text-gray-900 mb-3 line-clamp-2 group-hover:text-blue-600 transition-colors duration-300">
                                        {item.title}
                                    </h3>

                                    <p className="text-gray-600 mb-6 line-clamp-3 flex-grow">
                                        {item.excerpt}
                                    </p>

                                    <a 
                                        href={item.fullContent} 
                                        className="inline-flex items-center gap-2 text-blue-600 font-medium hover:text-blue-700 transition-colors duration-300 group/link"
                                    >
                                        <span>{t('newsSection.buttons.readMore')}</span>
                                        <span className="material-icons text-lg transform group-hover/link:translate-x-1 transition-transform duration-300">
                                            arrow_forward
                                        </span>
                                    </a>
                                </div>

                                {/* Hover Border Effect */}
                                <div className={`
                                    absolute inset-0 border-2 border-transparent rounded-2xl transition-all duration-300 pointer-events-none
                                    ${hoveredItem === item.id ? 'border-blue-500/30' : ''}
                                `}></div>
                            </div>
                        </div>
                    ))}
                </div>

                {/* View All Button */}
                <div className="text-center mt-16">
                    <a 
                        href="/news" 
                        className="inline-flex items-center gap-3 px-8 py-4 bg-gradient-to-r from-blue-600 to-purple-600 text-white rounded-full font-semibold text-lg hover:shadow-xl transform hover:-translate-y-1 transition-all duration-300"
                    >
                        <span>{t('newsSection.buttons.viewAllNews')}</span>
                        <span className="material-icons">east</span>
                    </a>
                </div>

                {/* Stats Bar */}
                <div className="mt-20 grid grid-cols-1 md:grid-cols-3 gap-8">
                    {[
                        { number: '50+', label: 'Events This Year', icon: 'event' },
                        { number: '200+', label: 'News Articles', icon: 'article' },
                        { number: '15K+', label: 'Community Members', icon: 'groups' }
                    ].map((stat, index) => (
                        <div 
                            key={index}
                            className="text-center p-6 bg-white/50 backdrop-blur-sm rounded-2xl border border-gray-100"
                        >
                            <div className="flex justify-center mb-4">
                                <div className="w-12 h-12 bg-gradient-to-r from-blue-500 to-purple-600 rounded-full flex items-center justify-center text-white">
                                    <span className="material-icons">{stat.icon}</span>
                                </div>
                            </div>
                            <div className="text-3xl font-bold text-gray-900 mb-2">{stat.number}</div>
                            <div className="text-gray-600">{stat.label}</div>
                        </div>
                    ))}
                </div>
            </div>
        </section>
    );
};

export default NewsSection;
